import{_ as a,o as r,c as e,a2 as l}from"./chunks/framework.Bjylvv1V.js";const b=JSON.parse('{"title":"퇴직정산 처리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/retirement.md","filePath":"guide/scenarios/retirement.md","lastUpdated":null}'),o={name:"guide/scenarios/retirement.md"};function i(s,t,n,d,h,c){return r(),e("div",null,[...t[0]||(t[0]=[l(`<h1 id="퇴직정산-처리" tabindex="-1">퇴직정산 처리 <a class="header-anchor" href="#퇴직정산-처리" aria-label="Permalink to &quot;퇴직정산 처리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 건당 약 20분 | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 수시 (퇴직 발생 시)</p></blockquote><p>직원 퇴직 시 평균임금을 기준으로 퇴직금을 계산하고, 퇴직소득세를 적용하여 정산한 뒤 원천징수영수증을 발급하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 인사기본정보 퇴사일 입력    (2분)   → 퇴사일 등록으로 정산 기준일 확정</span></span>
<span class="line"><span>2. 퇴직(중간)정산             (10분)  → 직원 선택 후 퇴직금 자동 계산 확인</span></span>
<span class="line"><span>3. 퇴직소득세 계산 확인        (3분)   → 세액 검토</span></span>
<span class="line"><span>4. 퇴직정산 출력              (5분)   → 퇴직소득 원천징수영수증 출력</span></span></code></pre></div><hr><h2 id="퇴직금-계산-원리" tabindex="-1">퇴직금 계산 원리 <a class="header-anchor" href="#퇴직금-계산-원리" aria-label="Permalink to &quot;퇴직금 계산 원리&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">퇴직금 계산 공식</p><p><strong>퇴직금 = 평균임금 × 30일 × (총재직일수 ÷ 365)</strong></p><ul><li><strong>평균임금</strong>: 퇴직 전 3개월 총급여 ÷ 해당 3개월 일수</li><li><strong>통상임금이 평균임금보다 높으면 통상임금을 적용</strong>합니다.</li></ul></div><h3 id="계산-예시" tabindex="-1">계산 예시 <a class="header-anchor" href="#계산-예시" aria-label="Permalink to &quot;계산 예시&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>퇴직 전 3개월 총급여</td><td>9,000,000원</td></tr><tr><td>해당 3개월 일수</td><td>92일</td></tr><tr><td><strong>평균임금</strong></td><td>9,000,000 ÷ 92 = <strong>97,826원</strong></td></tr><tr><td>총재직일수</td><td>1,825일 (5년)</td></tr><tr><td><strong>퇴직금</strong></td><td>97,826 × 30 × (1,825 ÷ 365) = <strong>14,999,978원</strong></td></tr></tbody></table><hr><h2 id="_1단계-인사기본정보-퇴사일-입력-2분" tabindex="-1">1단계: 인사기본정보 퇴사일 입력 (2분) <a class="header-anchor" href="#_1단계-인사기본정보-퇴사일-입력-2분" aria-label="Permalink to &quot;1단계: 인사기본정보 퇴사일 입력 (2분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/hr.html">인사관리</a> &gt; 인사기본정보 (PAY2010)</p></blockquote><p>퇴직정산의 기준일이 되는 퇴사일을 먼저 등록합니다.</p><ol><li>퇴직 직원 검색 후 선택</li><li><strong>퇴사일</strong> 입력</li><li>퇴사 사유 입력</li><li><strong>저장</strong> 클릭</li></ol><div class="warning custom-block"><p class="custom-block-title">퇴사일이 정산 기준</p><p>퇴사일을 기준으로 평균임금 계산 기간(퇴직 전 3개월)이 결정됩니다. 퇴사일이 정확해야 퇴직금이 정확하게 산출됩니다.</p></div><hr><h2 id="_2단계-퇴직-중간-정산-10분" tabindex="-1">2단계: 퇴직(중간)정산 (10분) <a class="header-anchor" href="#_2단계-퇴직-중간-정산-10분" aria-label="Permalink to &quot;2단계: 퇴직(중간)정산 (10분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/retirement.html">퇴직정산</a> &gt; 퇴직(중간)정산 (PAY5010)</p></blockquote><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>퇴직(중간)정산 화면 진입</li><li>해당 직원 선택</li><li>정산 구분 선택:</li></ol><table tabindex="0"><thead><tr><th>구분</th><th>설명</th></tr></thead><tbody><tr><td><strong>퇴직정산</strong></td><td>최종 퇴직 시 전체 재직 기간 정산</td></tr><tr><td><strong>중간정산</strong></td><td>법령이 허용하는 사유 발생 시 중도 정산</td></tr></tbody></table><ol start="4"><li>시스템이 자동 계산한 내용 확인:</li></ol><table tabindex="0"><thead><tr><th>항목</th><th>확인 내용</th></tr></thead><tbody><tr><td>재직 기간</td><td>입사일 ~ 퇴사일 총 일수</td></tr><tr><td>평균임금</td><td>퇴직 전 3개월 급여 기준</td></tr><tr><td>통상임금</td><td>평균임금과 비교 후 유리한 값 자동 적용</td></tr><tr><td>퇴직금</td><td>위 공식 적용 계산 결과</td></tr></tbody></table><ol start="5"><li>계산 결과 이상 없으면 <strong>확정</strong> 클릭</li></ol><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 재직 기간(입사일~퇴사일)이 정확한가?</li><li>[ ] 평균임금 계산 기간(3개월) 내 급여가 모두 반영되어 있는가?</li><li>[ ] 통상임금이 평균임금을 초과하는 경우 통상임금이 적용되었는가?</li><li>[ ] 중간정산 이력이 있다면 이후 기간만 산정되었는가?</li></ul><div class="tip custom-block"><p class="custom-block-title">통상임금 우선 적용</p><p>통상임금이 평균임금보다 높은 경우, 근로기준법에 따라 <strong>통상임금을 기준으로 계산</strong>합니다. 시스템이 자동으로 비교·적용합니다.</p></div><hr><h2 id="중간정산-처리-해당-시" tabindex="-1">중간정산 처리 (해당 시) <a class="header-anchor" href="#중간정산-처리-해당-시" aria-label="Permalink to &quot;중간정산 처리 (해당 시)&quot;">​</a></h2><p>중간정산은 아래 법령이 허용하는 사유에 한하여 진행할 수 있습니다.</p><h3 id="법령-허용-사유-주요" tabindex="-1">법령 허용 사유 (주요) <a class="header-anchor" href="#법령-허용-사유-주요" aria-label="Permalink to &quot;법령 허용 사유 (주요)&quot;">​</a></h3><ul><li>무주택 근로자의 주택 구입 또는 전세 보증금 납입</li><li>근로자 또는 부양가족의 6개월 이상 요양</li><li>퇴직급여제도 변경 (DC형 전환 등)</li><li>그 외 대통령령으로 정하는 사유</li></ul><div class="warning custom-block"><p class="custom-block-title">중간정산 후 재산정</p><p>중간정산 완료 후에는 <strong>해당 이후 기간만</strong>을 대상으로 새롭게 재직 기간이 산정됩니다. 중간정산 이전 기간은 이미 정산된 것으로 처리됩니다.</p></div><hr><h2 id="_3단계-퇴직소득세-계산-확인-3분" tabindex="-1">3단계: 퇴직소득세 계산 확인 (3분) <a class="header-anchor" href="#_3단계-퇴직소득세-계산-확인-3분" aria-label="Permalink to &quot;3단계: 퇴직소득세 계산 확인 (3분)&quot;">​</a></h2><p>퇴직(중간)정산 화면에서 퇴직금 계산과 함께 퇴직소득세가 자동 산출됩니다.</p><h3 id="퇴직소득세-확인-항목" tabindex="-1">퇴직소득세 확인 항목 <a class="header-anchor" href="#퇴직소득세-확인-항목" aria-label="Permalink to &quot;퇴직소득세 확인 항목&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>퇴직소득금액</td><td>퇴직금 - 비과세 항목</td></tr><tr><td>근속연수공제</td><td>재직 기간에 따른 공제</td></tr><tr><td>환산급여</td><td>(퇴직소득금액 - 근속연수공제) ÷ 근속연수 × 12</td></tr><tr><td>환산급여공제</td><td>환산급여에 따른 공제</td></tr><tr><td>과세표준</td><td>환산급여 - 환산급여공제</td></tr><tr><td><strong>퇴직소득세</strong></td><td>과세표준 × 세율 ÷ 12 × 근속연수</td></tr><tr><td><strong>지방소득세</strong></td><td>퇴직소득세 × 10%</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">IRP 이전 시 세금 이연</p><p>퇴직금을 IRP(개인형 퇴직연금)로 이전하면 <strong>퇴직소득세 납부를 연금 수령 시점까지 이연</strong>할 수 있습니다. 직원에게 안내하세요.</p></div><div class="danger custom-block"><p class="custom-block-title">신고·납부 기한: 다음 달 10일</p><p>퇴직소득세는 <strong>퇴직일이 속한 달의 다음 달 10일</strong>까지 신고·납부해야 합니다. 기한 초과 시 가산세가 부과됩니다.</p></div><hr><h2 id="_4단계-퇴직정산-출력-5분" tabindex="-1">4단계: 퇴직정산 출력 (5분) <a class="header-anchor" href="#_4단계-퇴직정산-출력-5분" aria-label="Permalink to &quot;4단계: 퇴직정산 출력 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/retirement.html">퇴직정산</a> &gt; 퇴직정산출력 (PAY5050)</p></blockquote><h3 id="출력-서류" tabindex="-1">출력 서류 <a class="header-anchor" href="#출력-서류" aria-label="Permalink to &quot;출력 서류&quot;">​</a></h3><table tabindex="0"><thead><tr><th>서류</th><th>용도</th></tr></thead><tbody><tr><td><strong>퇴직소득 원천징수영수증</strong></td><td>직원 교부용·세무 신고용</td></tr><tr><td><strong>퇴직금 정산 내역서</strong></td><td>관리용</td></tr></tbody></table><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>퇴직정산출력 화면 진입</li><li>해당 직원 및 정산 내역 선택</li><li>출력 서식 선택 후 <strong>출력</strong> 클릭</li><li>직원에게 퇴직소득 원천징수영수증 교부</li></ol><hr><h2 id="퇴직추계정산-현황-파악용" tabindex="-1">퇴직추계정산 (현황 파악용) <a class="header-anchor" href="#퇴직추계정산-현황-파악용" aria-label="Permalink to &quot;퇴직추계정산 (현황 파악용)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/retirement.html">퇴직정산</a> &gt; 퇴직추계정산 (PAY5020)</p></blockquote><p>실제 퇴직이 아닌 <strong>예상 퇴직금을 미리 계산</strong>하는 기능입니다. 퇴직충당금 적립 현황 파악이나 중기 재정 계획 수립 시 활용합니다.</p><h3 id="퇴직추계정산-조회" tabindex="-1">퇴직추계정산 조회 <a class="header-anchor" href="#퇴직추계정산-조회" aria-label="Permalink to &quot;퇴직추계정산 조회&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/retirement.html">퇴직정산</a> &gt; 퇴직추계정산조회 (PAY5040)</p></blockquote><p>전체 직원 또는 부서별 예상 퇴직금 현황을 조회합니다.</p><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="퇴직금-계산액이-예상과-다르게-나와요" tabindex="-1">퇴직금 계산액이 예상과 다르게 나와요 <a class="header-anchor" href="#퇴직금-계산액이-예상과-다르게-나와요" aria-label="Permalink to &quot;퇴직금 계산액이 예상과 다르게 나와요&quot;">​</a></h3><p><strong>원인</strong>: 평균임금 계산 기간 내 비정기 급여 포함 여부, 또는 재직일수 오류 <strong>해결</strong>: 퇴직 전 3개월 급여 내역을 <a href="/pay/salary.html">급여관리</a>에서 확인하고, 입사일·퇴사일이 정확한지 인사기본정보(PAY2010)에서 재확인하세요.</p><h3 id="통상임금이-평균임금보다-높은데-자동으로-적용이-안-돼요" tabindex="-1">통상임금이 평균임금보다 높은데 자동으로 적용이 안 돼요 <a class="header-anchor" href="#통상임금이-평균임금보다-높은데-자동으로-적용이-안-돼요" aria-label="Permalink to &quot;통상임금이 평균임금보다 높은데 자동으로 적용이 안 돼요&quot;">​</a></h3><p><strong>원인</strong>: 통상임금 설정이 급여기본정보에 반영되지 않은 경우 <strong>해결</strong>: <a href="/pay/salary.html">급여관리</a> &gt; 급여기본정보(PAY3010)에서 통상임금 항목이 올바르게 설정되어 있는지 확인하세요.</p><h3 id="중간정산-이후-재직-기간-계산이-이상해요" tabindex="-1">중간정산 이후 재직 기간 계산이 이상해요 <a class="header-anchor" href="#중간정산-이후-재직-기간-계산이-이상해요" aria-label="Permalink to &quot;중간정산 이후 재직 기간 계산이 이상해요&quot;">​</a></h3><p><strong>원인</strong>: 시스템에 중간정산 이력이 반영되지 않은 경우 <strong>해결</strong>: 퇴직(중간)정산(PAY5010) 화면에서 이전 중간정산 내역을 확인하고, 이후 기간만 산정되었는지 검토하세요.</p><h3 id="퇴직소득세-신고-기한을-놓쳤어요" tabindex="-1">퇴직소득세 신고 기한을 놓쳤어요 <a class="header-anchor" href="#퇴직소득세-신고-기한을-놓쳤어요" aria-label="Permalink to &quot;퇴직소득세 신고 기한을 놓쳤어요&quot;">​</a></h3><p><strong>원인</strong>: 퇴직일이 속한 달의 다음 달 10일 기한 미준수 <strong>해결</strong>: 즉시 홈택스를 통해 수정 신고하세요. 기한 초과 기간에 따른 가산세가 부과됩니다.</p><hr><h2 id="체크리스트-1" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트-1" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h2><h3 id="퇴직-처리-시" tabindex="-1">퇴직 처리 시 <a class="header-anchor" href="#퇴직-처리-시" aria-label="Permalink to &quot;퇴직 처리 시&quot;">​</a></h3><ul><li>[ ] 인사기본정보에 퇴사일이 입력되었는가?</li><li>[ ] 퇴직 전 3개월 급여가 모두 확정되었는가?</li><li>[ ] 평균임금 vs 통상임금 비교가 자동 적용되었는가?</li><li>[ ] 중간정산 이력이 있다면 반영되었는가?</li><li>[ ] 퇴직소득 원천징수영수증을 직원에게 교부했는가?</li><li>[ ] 퇴직소득세 신고·납부 기한(다음 달 10일)을 확인했는가?</li><li>[ ] IRP 이전 여부를 직원에게 안내했는가?</li></ul><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/pay/retirement.html">퇴직정산</a> - 퇴직금 계산·출력</li><li><a href="/pay/hr.html">인사관리</a> - 인사기본정보 (퇴사일 입력)</li><li><a href="/pay/salary.html">급여관리</a> - 급여기본정보 (통상임금 확인)</li><li><a href="/guide/scenarios/hr-manage.html">인사 관리</a> - 입퇴사 처리 전체 프로세스</li><li><a href="/guide/scenarios/payroll.html">급여 처리</a> - 급여 처리 프로세스</li></ul>`,72)])])}const g=a(o,[["render",i]]);export{b as __pageData,g as default};
